// shadcn
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";

// constants
const members = [
  {
    name: "Joseph William",
    role: "Professional",
    bio: "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
    avatar: "https://cdn.uiable.com/block/team7.png",
    initials: "JW",
  },
  {
    name: "Shirley Hoe",
    role: "Professional",
    bio: "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
    avatar: "https://cdn.uiable.com/block/team8.png",
    initials: "SH",
  },
  {
    name: "Joseph William",
    role: "Professional",
    bio: "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
    avatar: "https://cdn.uiable.com/block/team9.png",
    initials: "JW",
  },
];

//  ------------------------------ | TEAM 4 | ------------------------------  //

export default function team4() {
  return (
    <section className="py-16">
      <div className="mx-auto container px-6">
        <div className="grid grid-cols-12 mb-12">
          <div className="col-span-12 text-center">
            <h2>Our Crew</h2>
            <h5 className="text-muted-foreground font-light mt-3 mx-auto max-w-xl">
              At half-past eight the door opened, the policeman appeared and
              requesting them to follow him, led way to an adjoining hall.
            </h5>
          </div>
        </div>

        <div className="grid grid-cols-12 gap-8">
          {members.map((member, index) => (
            <div
              key={index}
              className="col-span-12 sm:col-span-6 lg:col-span-4 flex flex-col items-center text-center gap-4"
            >
              <Avatar className="size-26!">
                <AvatarImage src={member.avatar} alt={member.name} />
                <AvatarFallback>{member.initials}</AvatarFallback>
              </Avatar>
              <div>
                <h5 className="">{member.name}</h5>
                <h6 className="text-muted-foreground font-normal mt-1">
                  {member.role}
                </h6>
              </div>
              <h6 className="text-muted-foreground font-light">{member.bio}</h6>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
